<?php use PreConselho\Support\Csrf;ob_start();?><nav class="breadcrumbs" aria-label="Caminho"><a href="/">Painel</a> <span aria-hidden="true">›</span> Administração</nav><section class="page-heading"><div><p class="eyebrow">Configurações</p><h1>Administração</h1><p>Organize usuários, disciplinas, vínculos e períodos do pré-conselho.</p></div><a class="button" href="/admin/auditoria">Ver auditoria</a></section><nav class="admin-nav" aria-label="Seções da administração"><a href="#usuarios">Usuários</a><a href="#disciplinas">Disciplinas</a><a href="#vinculos">Vínculos</a><a href="#periodos">Períodos</a></nav>
<div class="grid"><section class="card admin-section" id="usuarios"><p class="eyebrow">Acesso</p><h2>Cadastrar usuário</h2><p class="helper">Crie o acesso e escolha o que a pessoa poderá fazer.</p><form method="post" action="/admin/usuarios"><input type="hidden" name="_csrf" value="<?=e(Csrf::token())?>"><label>Nome completo<input name="nome" required maxlength="150" placeholder="Ex.: Maria Aparecida"></label><label>E-mail institucional<input name="email" type="email" required placeholder="nome@escola.com.br"></label><label>Tipo de acesso<select name="perfil"><option value="PROFESSOR">Professor — preenche relatórios</option><option value="COORDENADOR">Coordenação — confere relatórios</option><option value="ADMIN">Administrador — gerencia o sistema</option></select></label><label>Senha inicial<input name="senha" type="password" minlength="10" required placeholder="No mínimo 10 caracteres"></label><button class="primary">Criar usuário</button></form></section>
<section class="card admin-section" id="disciplinas"><p class="eyebrow">Organização pedagógica</p><h2>Disciplinas</h2><p class="helper">Cadastre as disciplinas que poderão ser atribuídas aos professores.</p><form method="post" action="/admin/disciplinas"><input type="hidden" name="_csrf" value="<?=e(Csrf::token())?>"><label>Nome da disciplina<input name="nome" required maxlength="100" placeholder="Ex.: Língua Portuguesa"></label><button class="primary">Adicionar disciplina</button></form><?php if($disciplines):?><div class="discipline-list"><strong>Disciplinas cadastradas (<?=count($disciplines)?>)</strong><?php foreach($disciplines as$d):?><div class="discipline-item"><span><strong><?=e($d['nome'])?></strong><small><?=e($d['vinculos'])?> vínculo(s)</small></span><?php if((int)$d['vinculos']===0):?><form class="inline-form" method="post" action="/admin/disciplinas/<?=e($d['id'])?>/excluir"><input type="hidden" name="_csrf" value="<?=e(Csrf::token())?>"><button class="danger small-button" data-confirm="Excluir a disciplina <?=e($d['nome'])?>?">Excluir</button></form><?php else:?><span class="badge">Em uso</span><?php endif;?></div><?php endforeach;?></div><?php endif;?></section>
<section class="card admin-section binding-section" id="vinculos"><p class="eyebrow">Distribuição</p><h2>Vincular professor às turmas</h2><p class="helper">Escolha um professor e selecione todas as turmas e disciplinas que ele leciona. O sistema criará as combinações automaticamente.</p><form method="post" action="/admin/vinculos" id="binding-form"><input type="hidden" name="_csrf" value="<?=e(Csrf::token())?>"><div class="binding-step"><span class="step-number">1</span><div><label for="professor_id">Professor</label><?php if($professors):?><select id="professor_id" name="professor_id" required><option value="">Selecione um professor</option><?php foreach($professors as$p):?><option value="<?=e($p['id'])?>"><?=e($p['nome'])?> — <?=e($p['email'])?></option><?php endforeach;?></select><?php else:?><p class="error">Nenhum professor ativo cadastrado. Cadastre um usuário com acesso de professor primeiro.</p><?php endif;?></div></div>
<div class="binding-step"><span class="step-number">2</span><div><div class="choice-heading"><div><label>Turmas</label><p class="helper">Você pode marcar várias turmas.</p></div><?php if($classes):?><label class="search"><span class="sr-only">Buscar turma</span><span aria-hidden="true">⌕</span><input type="search" placeholder="Buscar turma ou ano" data-choice-filter="#class-choices"></label><?php endif;?></div><?php if($classesError):?><p class="error" role="alert"><?=e($classesError)?></p><?php elseif(!$classes):?><p class="empty-state compact">Nenhuma turma disponível na secretaria.</p><?php else:?><div class="choice-grid" id="class-choices"><?php foreach($classes as$class):?><label class="choice-card"><input type="checkbox" name="turma_ids[]" value="<?=e($class['id'])?>"><span><strong><?=e($class['nome_turma'])?></strong><small>Ano letivo: <?=e($class['ano_letivo'])?></small></span></label><?php endforeach;?></div><p class="selection-count"><strong data-selection-count="#class-choices">0</strong> turma(s) selecionada(s)</p><?php endif;?></div></div>
<div class="binding-step"><span class="step-number">3</span><div><label>Disciplinas</label><p class="helper">Marque todas as disciplinas ministradas pelo professor nas turmas selecionadas.</p><?php if(!$disciplines):?><p class="empty-state compact">Cadastre ao menos uma disciplina para continuar.</p><?php else:?><div class="choice-grid compact-choices" id="discipline-choices"><?php foreach($disciplines as$d):?><label class="choice-card"><input type="checkbox" name="disciplina_ids[]" value="<?=e($d['id'])?>"><span><strong><?=e($d['nome'])?></strong></span></label><?php endforeach;?></div><p class="selection-count"><strong data-selection-count="#discipline-choices">0</strong> disciplina(s) selecionada(s)</p><?php endif;?></div></div><div class="binding-submit"><p class="helper">Exemplo: 2 turmas × 3 disciplinas criarão 6 vínculos.</p><button class="primary" <?=(!$professors||!$classes||!$disciplines)?'disabled':''?>>Criar vínculos selecionados</button></div></form></section>
<section class="card admin-section" id="periodos"><p class="eyebrow">Calendário</p><h2>Criar período</h2><p class="helper">Defina a etapa e o prazo em que os professores poderão preencher.</p><form method="post" action="/admin/periodos"><input type="hidden" name="_csrf" value="<?=e(Csrf::token())?>"><label>Nome do período<input name="nome" required placeholder="Ex.: Pré-Conselho · 2º bimestre"></label><label>Ano letivo<input name="ano_letivo" type="number" min="2000" max="2100" value="<?=date('Y')?>" required></label><label>Etapa<input name="etapa" required placeholder="Ex.: 2º bimestre"></label><div class="grid"><label>Data de início<input name="data_inicio" type="date" required></label><label>Data final<input name="data_fim" type="date" required></label></div><button class="primary">Criar período</button></form></section></div>
<section class="card admin-section"><div class="section-heading"><div><p class="eyebrow">Calendário</p><h2>Períodos cadastrados</h2><p><?=count($periods)?> período(s)</p></div></div><?php if(!$periods):?><div class="empty-state compact"><p>Nenhum período cadastrado.</p></div><?php else:?><div class="table"><table><thead><tr><th>Período</th><th>Ano</th><th>Status</th><th>Ação</th></tr></thead><tbody><?php foreach($periods as$p):?><tr><td data-label="Período"><strong><?=e($p['nome'])?></strong></td><td data-label="Ano"><?=e($p['ano_letivo'])?></td><td data-label="Status"><span class="badge status-<?=e(strtolower($p['status']))?>"><?=e($p['status']==='RASCUNHO'?'Em preparação':($p['status']==='ABERTO'?'Aberto':'Encerrado'))?></span></td><td class="row-action"><?php if($p['status']==='RASCUNHO'):?><form class="inline-form" method="post" action="/admin/periodos/<?=e($p['id'])?>/abrir"><input type="hidden" name="_csrf" value="<?=e(Csrf::token())?>"><button class="primary" data-confirm="Abrir este período e gerar os relatórios dos vínculos ativos?">Abrir período</button></form><?php elseif($p['status']==='ABERTO'):?><form class="inline-form" method="post" action="/admin/periodos/<?=e($p['id'])?>/encerrar"><input type="hidden" name="_csrf" value="<?=e(Csrf::token())?>"><button class="danger" data-confirm="Encerrar o período? Esta ação bloqueará novas edições.">Encerrar período</button></form><?php else:?><span class="helper">Sem ações</span><?php endif;?></td></tr><?php endforeach;?></tbody></table></div><?php endif;?></section>
<section class="card admin-section"><div class="section-heading"><div><p class="eyebrow">Acesso</p><h2>Usuários cadastrados</h2><p><?=count($users)?> usuário(s)</p></div><label class="search"><span class="sr-only">Buscar usuário</span><span aria-hidden="true">⌕</span><input type="search" placeholder="Buscar usuário" data-table-search="#users-table"></label></div><div class="table"><table id="users-table"><thead><tr><th>Usuário</th><th>ID</th><th>Tipo de acesso</th><th>Estado</th><th>Ação</th></tr></thead><tbody><?php foreach($users as$u):?><tr><td data-label="Usuário"><strong><?=e($u['nome'])?></strong><small><?=e($u['email'])?></small></td><td data-label="ID"><?=e($u['id'])?></td><td data-label="Acesso"><?=e(['PROFESSOR'=>'Professor','COORDENADOR'=>'Coordenação','ADMIN'=>'Administrador'][$u['perfil']]??$u['perfil'])?></td><td data-label="Estado"><span class="badge status-<?=$u['ativo']?'aprovado':'pendente'?>"><?=e($u['ativo']?'Ativo':'Inativo')?></span></td><td class="row-action"><?php if((int)$u['id']!==(int)$_SESSION['user']['id']):?><form class="inline-form" method="post" action="/admin/usuarios/<?=e($u['id'])?>/alternar"><input type="hidden" name="_csrf" value="<?=e(Csrf::token())?>"><button class="<?=$u['ativo']?'danger':''?>" data-confirm="Confirma que deseja <?=e($u['ativo']?'desativar':'ativar')?> este usuário?"><?=e($u['ativo']?'Desativar':'Ativar')?></button></form><?php else:?><span class="helper">Usuário atual</span><?php endif;?></td></tr><?php endforeach;?></tbody></table></div></section><?php $content=ob_get_clean();require __DIR__.'/layout.php';
